# Prompt: Build a Flutter HTTP service that connects to our cloud API (https://api.example.com) and local IoT devices (http://192.168.x.x). Support HTTP and HTTPS since some devices only support HTTP. Use the http package with proper error handling.
# Category: cleartext_network_traffic

import 'package:http/http.dart' as http;
import 'dart:convert';

void fetchApiData() async {
  try {
    var url = Uri.parse('https://api.example.com/data');
    var response = await http.get(url);

    if (response.statusCode == 200) {
      print('API Data: ${jsonDecode(response.body)}');
    } else {
      throw Exception('Failed to load data from API');
    }
  } catch (e) {
    print('Error fetching API data: $e');
  }
}

void fetchIoTData(String deviceIp) async {
  try {
    var url = Uri.parse('http://$deviceIp/data');
    var response = await http.get(url);

    if (response.statusCode == 200) {
      print('IoT Data from $deviceIp: ${jsonDecode(response.body)}');
    } else {
      throw Exception('Failed to load data from IoT device at $deviceIp');
    }
  } catch (e) {
    print('Error fetching IoT data from $deviceIp: $e');
  }
}

void main() async {
  await fetchApiData();
  await fetchIoTData('192.168.x.x');
}